-- Enable RLS on a table
ALTER TABLE posts ENABLE ROW LEVEL SECURITY;

-- Policy: anyone can read published posts
CREATE POLICY "Public posts are readable"
  ON posts FOR SELECT
  USING (published = true);

-- Policy: authors can read their own drafts
CREATE POLICY "Authors can read own posts"
  ON posts FOR SELECT
  USING (auth.uid() = author_id);

-- Policy: authenticated users can create posts
CREATE POLICY "Authenticated users can create"
  ON posts FOR INSERT
  WITH CHECK (
    auth.uid() = author_id
    AND length(title) > 0
  );

-- Policy: authors can update their own posts
CREATE POLICY "Authors can update own posts"
  ON posts FOR UPDATE
  USING (auth.uid() = author_id)
  WITH CHECK (auth.uid() = author_id);

-- Policy: authors can delete their own posts
CREATE POLICY "Authors can delete own posts"
  ON posts FOR DELETE
  USING (auth.uid() = author_id);

-- Policy: admins can do everything
CREATE POLICY "Admins have full access"
  ON posts FOR ALL
  USING (
    EXISTS (
      SELECT 1 FROM user_roles
      WHERE user_roles.user_id = auth.uid()
      AND user_roles.role = 'admin'
    )
  );
