import { createClient } from "@supabase/supabase-js";

const supabase = createClient(SUPABASE_URL, SUPABASE_KEY);

// Listen to table changes
const channel = supabase
  .channel("posts-changes")
  .on(
    "postgres_changes",
    { event: "*", schema: "public", table: "posts" },
    (payload) => {
      console.log("Change:", payload.eventType, payload.new);
      // payload.eventType: "INSERT" | "UPDATE" | "DELETE"
      // payload.new: new row data
      // payload.old: old row data (for UPDATE/DELETE)
    }
  )
  .subscribe();

// Cleanup on unmount
channel.unsubscribe();

// Broadcast — custom pub/sub (not tied to database)
const room = supabase.channel("room-1");

room.on("broadcast", { event: "cursor-move" }, (payload) => {
  console.log("Cursor moved:", payload.payload);
});

room.subscribe();

// Send broadcast
room.send({
  type: "broadcast",
  event: "cursor-move",
  payload: { x: 100, y: 200 }
});

// Presence — track who's online
const presenceChannel = supabase.channel("online-users");

presenceChannel
  .on("presence", { event: "sync" }, () => {
    const state = presenceChannel.presenceState();
    console.log("Online:", Object.keys(state).length);
  })
  .subscribe(async (status) => {
    if (status === "SUBSCRIBED") {
      await presenceChannel.track({
        user_id: userId,
        online_at: new Date().toISOString()
      });
    }
  });
