import { createClient } from "@supabase/supabase-js";

const supabase = createClient(SUPABASE_URL, SUPABASE_KEY);

// Upload a file
async function uploadAvatar(file, userId) {
  const filePath = `${userId}/avatar.${file.name.split(".").pop()}`;

  const { data, error } = await supabase.storage
    .from("avatars")
    .upload(filePath, file, {
      cacheControl: "3600",
      upsert: true  // overwrite if exists
    });

  if (error) throw error;

  // Get public URL
  const { data: { publicUrl } } = supabase.storage
    .from("avatars")
    .getPublicUrl(filePath);

  return publicUrl;
}

// Upload with progress
async function uploadWithProgress(file, bucket, path) {
  const { data, error } = await supabase.storage
    .from(bucket)
    .upload(path, file, {
      onUploadProgress: (progress) => {
        const pct = Math.round((progress.loaded / progress.total) * 100);
        console.log(`Upload progress: ${pct}%`);
      }
    });
  return data;
}

// Signed URL for private files (expires in 1 hour)
async function getSignedUrl(bucket, path) {
  const { data, error } = await supabase.storage
    .from(bucket)
    .createSignedUrl(path, 3600); // 1 hour
  return data?.signedUrl;
}

// List files in a bucket
async function listFiles(bucket, folder) {
  const { data, error } = await supabase.storage
    .from(bucket)
    .list(folder, {
      limit: 100,
      offset: 0,
      sortBy: { column: "created_at", order: "desc" }
    });
  return data;
}

// Delete file
await supabase.storage.from("avatars").delete(["user123/avatar.jpg"]);

// Transform images (resize, crop)
const { data: { publicUrl } } = supabase.storage
  .from("images")
  .getPublicUrl("photo.jpg", {
    transform: {
      width: 200,
      height: 200,
      resize: "cover"
    }
  });
