// Complete solution: User avatar upload with RLS-protected storage
import { createClient } from '@supabase/supabase-js';

const supabase = createClient(SUPABASE_URL, SUPABASE_KEY);

// Step 1: Upload with progress tracking
async function uploadAvatar(file, userId) {
  const ext = file.name.split('.').pop();
  const path = `${userId}/avatar.${ext}`;

  const { data, error } = await supabase.storage
    .from('avatars')
    .upload(path, file, { upsert: true });

  if (error) throw error;

  // Step 2: Get public URL and store reference
  const { data: { publicUrl } } = supabase.storage
    .from('avatars')
    .getPublicUrl(path);

  // Step 3: Update user profile with avatar URL
  await supabase
    .from('profiles')
    .update({ avatar_url: publicUrl })
    .eq('id', userId);

  return publicUrl;
}

// Step 4: Generate signed URL for private files
async function getPrivateDocument(path, expiresIn = 3600) {
  const { data } = await supabase.storage
    .from('documents')
    .createSignedUrl(path, expiresIn);
  return data?.signedUrl;
}
